mapper.select:
SELECT bm.barcode, bm.source_no AS sourceNo, bm.item_no AS itemNo, bm.item_name AS itemName, bm.item_spec AS itemSpec, bm.qty, bm.lot_desc AS lotDesc, bm.lot_date AS lotDate, W.WAREHOUSE_CODE AS warehouseCode, W.WAREHOUSE_NAME AS warehouseName, B.BIN_CODE AS binCode, U.UNIT_CODE AS unitNo, U.UNIT_NAME AS unitName, PLANT.PLANT_CODE AS shjg FROM bm_barcode_detail bm LEFT JOIN MO ON bm.source_no COLLATE Chinese_PRC_CS_AS = MO.DOC_NO LEFT JOIN UNIT U ON MO.BUSINESS_UNIT_ID = U.UNIT_ID LEFT JOIN ITEM I ON MO.ITEM_ID = I.ITEM_BUSINESS_ID LEFT JOIN ITEM_PLANT IP ON I.ITEM_BUSINESS_ID = IP.ITEM_ID AND MO.Owner_Org_ROid=IP.Owner_Org_ROid LEFT JOIN WAREHOUSE W ON W.WAREHOUSE_ID = IP.INBOUND_WAREHOUSE_ID LEFT JOIN BIN B ON B.BIN_ID = IP.INBOUND_BIN_ID LEFT JOIN PLANT ON MO.Owner_Org_ROid = PLANT.PLANT_ID
source_no = #{docNo}
AND barcode = #{barcode}

mapper.update:
        UPDATE MD
        SET MD.WAREHOUSE_ID = (
            SELECT WA.WAREHOUSE_ID
            FROM WAREHOUSE WA
            WHERE WA.WAREHOUSE_CODE = #{warehouseCode}
        )
            FROM MO_RECEIPT_REQUISTION M
JOIN MO_RECEIPT_REQUISTION_D MD ON MD.MO_RECEIPT_REQUISTION_ID = M.MO_RECEIPT_REQUISTION_ID
        WHERE M.DOC_NO = #{docNo};

mapper.select:
SELECT TOP 100 MO.DOC_NO AS docNo, CAST(MO.DOC_DATE AS NVARCHAR(10)) AS docDate, MO_D.ITEM_DESCRIPTION AS itemName, MO.ITEM_DESCRIPTION AS productName, MO_D.ITEM_SPECIFICATION AS itemSpec, ITEM1.ITEM_CODE AS productCode, LOW_ITEM.ITEM_CODE AS itemCode, UNIT.UNIT_CODE AS unitNo, CAST(sum(MO_D.REQU_INCLUDE_MULT_QTY) AS NUMERIC(16,4)) AS sourceDocQty, CAST(sum((MO_D.REQU_INCLUDE_MULT_QTY - MO_D.ISSUED_QTY)) AS NUMERIC(16,4)) AS applyQty, CAST(ISNULL(ITEM_WAREHOUSE_BIN.TOTAL_INVENTORY_QTY, 0) AS NUMERIC(16,4)) AS stockQty, ITEM_WAREHOUSE_BIN.WAREHOUSE_CODE AS warehouseCode, ISNULL(ITEM_WAREHOUSE_BIN.WAREHOUSE_NAME,'') AS warehouseName, ISNULL(ITEM_WAREHOUSE_BIN.BIN_CODE,'') AS binCode, MO_D.SequenceNumber AS xh, CAST(MO_D.ISSUED_QTY AS NUMERIC(16,4)) AS issuedQty, MO_D.REMARK as remark FROM MO INNER JOIN PLANT ON MO.Owner_Org_ROid = PLANT.PLANT_ID INNER JOIN MO_D ON MO.MO_ID = MO_D.MO_ID INNER JOIN ITEM AS ITEM1 ON MO.ITEM_ID = ITEM1.ITEM_BUSINESS_ID INNER JOIN ITEM AS LOW_ITEM ON MO_D.ITEM_ID = LOW_ITEM.ITEM_BUSINESS_ID LEFT OUTER JOIN ITEM_FEATURE ON MO_D.ITEM_FEATURE_ID=ITEM_FEATURE.ITEM_FEATURE_ID INNER JOIN UNIT AS UNIT ON LOW_ITEM.STOCK_UNIT_ID = UNIT.UNIT_ID LEFT OUTER JOIN (SELECT ITEM_WAREHOUSE_BIN.ITEM_ID AS ITEM_ID, WAREHOUSE.WAREHOUSE_ID AS WAREHOUSE_ID, CONVERT(nvarchar(10), ISNULL(WAREHOUSE.WAREHOUSE_CODE , '')) AS WAREHOUSE_CODE, WAREHOUSE.WAREHOUSE_NAME AS WAREHOUSE_NAME, ITEM_WAREHOUSE_BIN.ITEM_FEATURE_ID AS ITEM_FEATURE_ID, ITEM_WAREHOUSE_BIN.Owner_Org_ROid AS Owner_Org_ROid , ITEM_WAREHOUSE_BIN.BIN_ID AS BIN_ID, BIN.BIN_CODE AS BIN_CODE, CAST(SUM(ITEM_WAREHOUSE_BIN.INVENTORY_QTY) AS NUMERIC(16,4)) AS TOTAL_INVENTORY_QTY ,CAST(SUM(ITEM_WAREHOUSE_BIN.SECOND_QTY) AS NUMERIC(16,4)) AS TOTAL_SECOND_QTY FROM ITEM_WAREHOUSE_BIN INNER JOIN WAREHOUSE ON ITEM_WAREHOUSE_BIN.WAREHOUSE_ID=WAREHOUSE.WAREHOUSE_ID LEFT JOIN BIN ON BIN.BIN_ID=ITEM_WAREHOUSE_BIN.BIN_ID GROUP BY ITEM_WAREHOUSE_BIN.ITEM_ID, WAREHOUSE.WAREHOUSE_ID,ITEM_WAREHOUSE_BIN.ITEM_FEATURE_ID, ITEM_WAREHOUSE_BIN.Owner_Org_ROid,ITEM_WAREHOUSE_BIN.BIN_ID,WAREHOUSE.WAREHOUSE_CODE,BIN.BIN_CODE,WAREHOUSE.WAREHOUSE_NAME ) AS ITEM_WAREHOUSE_BIN ON ITEM_WAREHOUSE_BIN.ITEM_ID = MO_D.ITEM_ID AND ITEM_WAREHOUSE_BIN.ITEM_FEATURE_ID = MO_D.ITEM_FEATURE_ID AND ITEM_WAREHOUSE_BIN.WAREHOUSE_ID =MO_D.WAREHOUSE_ID AND ITEM_WAREHOUSE_BIN.Owner_Org_ROid = MO.Owner_Org_ROid AND ITEM_WAREHOUSE_BIN.WAREHOUSE_ID=MO_D.WAREHOUSE_ID AND ITEM_WAREHOUSE_BIN.BIN_ID=MO_D.BIN_ID INNER JOIN ITEM_PLANT ON ITEM_PLANT.ITEM_ID = MO_D.ITEM_ID AND ITEM_PLANT.Owner_Org_ROid = MO.Owner_Org_ROid LEFT JOIN UNIT AS UNIT_02 ON LOW_ITEM.SECOND_UNIT_ID = UNIT_02.UNIT_ID LEFT JOIN dbo.UNIT AS UNIT_04 ON LOW_ITEM.STOCK_UNIT_ID=UNIT_04.UNIT_ID LEFT JOIN ITEM_LOT AS ITEM_LOT ON ITEM_LOT.ITEM_LOT_ID=MO_D.ITEM_LOT_ID LEFT JOIN OPERATION ON OPERATION.OPERATION_ID=MO_D .OPERATION_ID WHERE PLANT.PLANT_CODE = '1'
and MO.DOC_NO like concat('%',#{docNo},'%')
and CAST(MO.DOC_DATE AS NVARCHAR(10)) >= #{startDate}
and CAST(MO.DOC_DATE AS NVARCHAR(10)) <= #{endDate}
AND MO.ApproveStatus = N'Y' AND ITEM_PLANT.ISSUE_TYPE = N'0' AND MO.STATUS NOT IN (N'Y', N'y') AND MO_D.REQU_INCLUDE_MULT_QTY > MO_D.ISSUED_QTY AND MO_D.ITEM_TYPE <>'4'
group by MO.DOC_NO,MO.ITEM_DESCRIPTION,MO.ITEM_SPECIFICATION, LOW_ITEM.ITEM_CODE,MO_D.ITEM_DESCRIPTION ,MO_D.ITEM_SPECIFICATION , ITEM_FEATURE.ITEM_FEATURE_CODE,UNIT.UNIT_CODE ,ITEM_WAREHOUSE_BIN.TOTAL_INVENTORY_QTY ,ITEM_WAREHOUSE_BIN.TOTAL_SECOND_QTY ,UNIT.UNIT_NAME ,UNIT_02.UNIT_CODE ,UNIT_02.UNIT_NAME ,UNIT_04.UNIT_CODE ,UNIT_04.UNIT_NAME ,UNIT_04.DICIMAL_DIGIT ,LOW_ITEM.SECOND_UNIT_ID ,UNIT.UNIT_ID ,LOW_ITEM.ITEM_BUSINESS_ID ,LOW_ITEM.STOCK_UNIT_ID ,ITEM_WAREHOUSE_BIN.WAREHOUSE_CODE ,ITEM_WAREHOUSE_BIN.BIN_CODE ,ITEM_LOT.LOT_CODE,UNIT.DICIMAL_DIGIT ,MO.DOC_NO ,ITEM1.ITEM_CODE ,ITEM_WAREHOUSE_BIN.WAREHOUSE_NAME, MO.DOC_DATE, MO_D.SequenceNumber, MO_D.ISSUED_QTY , MO_D.REMARK, MO.ITEM_DESCRIPTION order by MO.DOC_DATE DESC, MO.DOC_NO ASC, MO_D.SequenceNumber ASC

SELECT TOP 2 docNo, itemCode, itemName, workCenterCode, workCenterName, moTypeName FROM ( SELECT A.DOC_NO AS docNo, ITEM.ITEM_CODE AS itemCode, A.ITEM_DESCRIPTION AS itemName, ISNULL(WC.WORK_CENTER_CODE, '') AS workCenterCode, ISNULL(WC.WORK_CENTER_NAME, '') AS workCenterName, N'装配' AS moTypeName FROM SN_ITEM_RECORD SIR INNER JOIN MO A ON SIR.SOURCE_ID_ROid = A.MO_ID INNER JOIN PLANT ON A.Owner_Org_ROid = PLANT.PLANT_ID INNER JOIN ITEM ON A.ITEM_ID = ITEM.ITEM_BUSINESS_ID LEFT JOIN WORK_CENTER WC ON A.SOURCE_ID_ROid = WC.WORK_CENTER_ID AND A.SOURCE_ID_RTK = N'WORK_CENTER' WHERE A.ApproveStatus = 'Y' AND SIR.SN_NO = #{frameNo} AND A.DOC_NO LIKE '5106%' AND EXISTS ( SELECT 1 FROM ISSUE_RECEIPT_D IRD INNER JOIN ISSUE_RECEIPT IR ON IR.ISSUE_RECEIPT_ID = IRD.ISSUE_RECEIPT_ID AND IR.CATEGORY = N'56' WHERE IRD.MO_ID = A.MO_ID AND IR.ApproveStatus = N'Y' AND IRD.ISSUE_RECEIPT_QTY > 0 )
AND PLANT.PLANT_CODE = #{plantCode}
AND A.DOC_NO LIKE concat(#{docType}, '%')
AND (WC.WORK_CENTER_CODE LIKE concat('%', #{workCenter}, '%') OR WC.WORK_CENTER_NAME LIKE concat('%', #{workCenter}, '%'))
UNION ALL
SELECT A.DOC_NO AS docNo, ITEM.ITEM_CODE AS itemCode, A.ITEM_DESCRIPTION AS itemName, ISNULL(WC.WORK_CENTER_CODE, '') AS workCenterCode, ISNULL(WC.WORK_CENTER_NAME, '') AS workCenterName, N'包装' AS moTypeName FROM SN_ITEM_RECORD SIR INNER JOIN MO A ON SIR.UDF051 = A.MO_ID INNER JOIN PLANT ON A.Owner_Org_ROid = PLANT.PLANT_ID INNER JOIN ITEM ON A.ITEM_ID = ITEM.ITEM_BUSINESS_ID LEFT JOIN WORK_CENTER WC ON A.SOURCE_ID_ROid = WC.WORK_CENTER_ID AND A.SOURCE_ID_RTK = N'WORK_CENTER' WHERE A.ApproveStatus = 'Y' AND SIR.SN_NO = #{frameNo} AND A.DOC_NO LIKE '5156%' AND EXISTS ( SELECT 1 FROM ISSUE_RECEIPT_D IRD INNER JOIN ISSUE_RECEIPT IR ON IR.ISSUE_RECEIPT_ID = IRD.ISSUE_RECEIPT_ID AND IR.CATEGORY = N'56' WHERE IRD.MO_ID = A.MO_ID AND IR.ApproveStatus = N'Y' AND IRD.ISSUE_RECEIPT_QTY > 0 )
AND PLANT.PLANT_CODE = #{plantCode}
AND A.DOC_NO LIKE concat(#{docType}, '%')
AND (WC.WORK_CENTER_CODE LIKE concat('%', #{workCenter}, '%') OR WC.WORK_CENTER_NAME LIKE concat('%', #{workCenter}, '%'))
) AS FrameMo ORDER BY docNo ASC

SELECT TOP 200 MO.DOC_NO AS docNo, CAST(MO.DOC_DATE AS NVARCHAR(10)) AS docDate, ISNULL(ADMIN_UNIT.ADMIN_UNIT_CODE, '') AS departmentCode, ISNULL(ADMIN_UNIT.ADMIN_UNIT_NAME, '') AS departmentName, ITEM.ITEM_CODE AS itemCode, MO.ITEM_DESCRIPTION AS itemName, LOW_ITEM.ITEM_CODE AS lowOrderItemCode, ISNULL(IRD.ITEM_DESCRIPTION, '') AS lowOrderItemName, ISNULL(IRD.ITEM_SPECIFICATION, '') AS lowOrderItemSpec, UNIT.UNIT_CODE AS unitCode, ISNULL(WAREHOUSE.WAREHOUSE_CODE, '') AS warehouseCode, ISNULL(WAREHOUSE.WAREHOUSE_NAME, '') AS warehouseName, ISNULL(BIN.BIN_CODE, '') AS binCode, ISNULL(IL.LOT_CODE, '') AS lotNo, ISNULL(PLANT.PLANT_CODE, '') AS orgNo, CAST(IRD.ISSUE_RECEIPT_QTY AS NUMERIC(16, 4)) AS issuedQty, CAST(IRD.ISSUE_RECEIPT_QTY AS NUMERIC(16, 4)) AS applyQty, 0 AS stockQty, CAST(IRD.SequenceNumber AS NVARCHAR(20)) AS xh, CASE WHEN LOW_ITEM.LOT_CONTROL = N'N' THEN 0 ELSE 1 END AS lotControl, ISNULL(IRD.REMARK, '') AS remark, ISNULL(( SELECT TOP 1 ISNULL(MOD.REMARK, '') FROM MO_D MOD WHERE MOD.MO_ID = MO.MO_ID AND MOD.ITEM_ID = IRD.ITEM_ID ORDER BY MOD.SequenceNumber ), '') AS moRemark FROM ISSUE_RECEIPT_D IRD INNER JOIN ISSUE_RECEIPT IR ON IR.ISSUE_RECEIPT_ID = IRD.ISSUE_RECEIPT_ID AND IR.CATEGORY = N'56' AND IR.ApproveStatus = N'Y' INNER JOIN MO ON MO.MO_ID = IRD.MO_ID AND MO.ApproveStatus = 'Y' AND MO.DOC_NO = #{docNo} INNER JOIN PLANT ON MO.Owner_Org_ROid = PLANT.PLANT_ID INNER JOIN ITEM ON MO.ITEM_ID = ITEM.ITEM_BUSINESS_ID INNER JOIN ITEM AS LOW_ITEM ON IRD.ITEM_ID = LOW_ITEM.ITEM_BUSINESS_ID INNER JOIN UNIT ON LOW_ITEM.STOCK_UNIT_ID = UNIT.UNIT_ID LEFT JOIN ADMIN_UNIT ON MO.Owner_Dept = ADMIN_UNIT.ADMIN_UNIT_ID LEFT JOIN ITEM_LOT IL ON IRD.ITEM_LOT_ID = IL.ITEM_LOT_ID LEFT JOIN WAREHOUSE ON IRD.WAREHOUSE_ID = WAREHOUSE.WAREHOUSE_ID LEFT JOIN BIN ON IRD.BIN_ID = BIN.BIN_ID WHERE IRD.ISSUE_RECEIPT_QTY > 0
AND PLANT.PLANT_CODE = #{plantCode}
AND (ITEM.ITEM_CODE LIKE concat('%',#{item},'%') OR MO.ITEM_DESCRIPTION LIKE concat('%',#{item},'%'))
AND (LOW_ITEM.ITEM_CODE LIKE concat('%',#{lowItem},'%') OR IRD.ITEM_DESCRIPTION LIKE concat('%',#{lowItem},'%'))
AND (ADMIN_UNIT.ADMIN_UNIT_CODE LIKE concat('%',#{departmentName},'%') OR ADMIN_UNIT.ADMIN_UNIT_NAME LIKE concat('%',#{departmentName},'%'))
AND MO.DOC_DATE >= #{startDate}
AND MO.DOC_DATE <= #{endDate}
ORDER BY IRD.SequenceNumber ASC

SELECT DISTINCT TOP 10 A.DOC_NO AS docNo, A.DOC_DATE AS DOC_DATE, CAST(A.DOC_DATE AS NVARCHAR(10)) AS createDate, ISNULL(B.ADMIN_UNIT_CODE, N' ') AS departmentNo, ISNULL(B.ADMIN_UNIT_NAME, N' ') AS departmentName, ISNULL(C.EMPLOYEE_CODE, N' ') AS employeeNo, ISNULL(C.EMPLOYEE_NAME, N' ') AS employeeName, '' AS customerNo, '' AS customerName, '' AS supplierNo, '' AS supplierName FROM ISSUE_RECEIPT AS A INNER JOIN ISSUE_RECEIPT_D AS D ON A.ISSUE_RECEIPT_ID = D.ISSUE_RECEIPT_ID INNER JOIN PLANT ON A.Owner_Org_ROid = PLANT.PLANT_ID LEFT JOIN ADMIN_UNIT AS B ON A.Owner_Dept = B.ADMIN_UNIT_ID LEFT JOIN EMPLOYEE AS C ON A.Owner_Emp = C.EMPLOYEE_ID INNER JOIN ITEM ON D.ITEM_ID = ITEM.ITEM_BUSINESS_ID WHERE PLANT.PLANT_CODE = '1' AND A.ApproveStatus = N'N' AND A.CATEGORY = N'57'
and A.DOC_NO =#{docNo}
ORDER BY A.DOC_DATE DESC, A.DOC_NO ASC

SELECT [MO_RECEIPT_REQUISTION].[DOC_NO] AS [docNo] , CAST([MO_RECEIPT_REQUISTION].[DOC_DATE] AS NVARCHAR(10)) AS [docDate] ,ISNULL([ADMIN_UNIT].[ADMIN_UNIT_CODE] ,N' ') AS [departmentNo] ,ISNULL([ADMIN_UNIT].[ADMIN_UNIT_NAME] ,N' ') AS [departmentName] ,ISNULL([EMPLOYEE].[EMPLOYEE_CODE] ,N' ') AS [employeeNo] ,ISNULL([EMPLOYEE].[EMPLOYEE_NAME] ,N' ') AS [employeeName] ,[ITEM].[ITEM_CODE] AS [itemNo] ,ISNULL([ITEM_FEATURE].[ITEM_FEATURE_CODE] ,N' ') AS [productCode] ,'' AS stockCode ,[MO_RECEIPT_REQUISTION_D].[ITEM_DESCRIPTION] AS [itemName] ,[MO_RECEIPT_REQUISTION_D].[ITEM_SPECIFICATION] AS [itemSpec] ,[UNIT].[UNIT_CODE] AS [unitNo] ,0 AS stockQty ,SUM(MO_RECEIPT_REQUISTION_D.ACCEPTED_QTY +MO_RECEIPT_REQUISTION_D.CONCESSION_QTY-MO_RECEIPT_REQUISTION_D.RECEIPT_QTY ) AS [applyQty] ,0 AS [scanSumQty] ,'' AS customerNo ,'' AS customerName ,'' AS supplierNo ,'' AS supplierName , ISNULL([WAREHOUSE].[WAREHOUSE_CODE] ,N' ') AS warehouseCode , ISNULL([BIN].[BIN_CODE] ,N' ') AS binCode , ISNULL([ITEM_LOT].[LOT_CODE] ,N' ') AS lotNo ,UNIT.UNIT_NAME as unitName --交易单位名称 ,ISNULL(UNIT_02.UNIT_CODE,'') AS referenceUnitNo --参考单位编码(第二单位) ,ISNULL(UNIT_02.UNIT_NAME,'') AS referenceUnitName--参考单位名称 ,dbo.[UNIT_CONVERT](ITEM.ITEM_BUSINESS_ID,UNIT.UNIT_ID,SUM(MO_RECEIPT_REQUISTION_D.ACCEPTED_QTY +MO_RECEIPT_REQUISTION_D.CONCESSION_QTY-MO_RECEIPT_REQUISTION_D.RECEIPT_QTY ),ITEM.SECOND_UNIT_ID,0) AS referenceQty --参考单位数量 ,'' AS valuationUnitNo --计价单位编码 ,''AS valuationUnitName --计价单位名称 ,0 AS valuationQty --计价单位数量 ,UNIT_04.UNIT_CODE AS stockUnitNo --库存单位编码 ,UNIT_04.UNIT_NAME AS stockUnitName --库存单位名称 ,UNIT_04.DICIMAL_DIGIT AS stockKeep --库存单位小数位数 --,dbo.[UNIT_CONVERT](ITEM.ITEM_BUSINESS_ID,UNIT.UNIT_ID,SUM(MO_RECEIPT_REQUISTION_D.ACCEPTED_QTY +MO_RECEIPT_REQUISTION_D.CONCESSION_QTY-MO_RECEIPT_REQUISTION_D.RECEIPT_QTY ),ITEM.STOCK_UNIT_ID,0) AS stockUnitQty --库存单位数量 ,SUM(MO_RECEIPT_REQUISTION_D.ACCEPTED_QTY) AS sourceDocQty ,0 keep, 1 rate FROM [MO_RECEIPT_REQUISTION] AS [MO_RECEIPT_REQUISTION] INNER JOIN [MO_RECEIPT_REQUISTION_D] AS [MO_RECEIPT_REQUISTION_D] ON [MO_RECEIPT_REQUISTION_D].[MO_RECEIPT_REQUISTION_ID] = [MO_RECEIPT_REQUISTION].[MO_RECEIPT_REQUISTION_ID] LEFT OUTER JOIN [ADMIN_UNIT] AS [ADMIN_UNIT] ON [MO_RECEIPT_REQUISTION].[Owner_Dept] = [ADMIN_UNIT].[ADMIN_UNIT_ID] LEFT OUTER JOIN [EMPLOYEE] AS [EMPLOYEE] ON [MO_RECEIPT_REQUISTION].[Owner_Emp] = [EMPLOYEE].[EMPLOYEE_ID] INNER JOIN [ITEM] AS [ITEM] ON [MO_RECEIPT_REQUISTION_D].[ITEM_ID] = [ITEM].[ITEM_BUSINESS_ID] LEFT OUTER JOIN [ITEM_FEATURE] AS [ITEM_FEATURE] ON [ITEM_FEATURE].[ITEM_FEATURE_ID] = [MO_RECEIPT_REQUISTION_D].[ITEM_FEATURE_ID] INNER JOIN [UNIT] AS [UNIT] ON [MO_RECEIPT_REQUISTION_D].[BUSINESS_UNIT_ID] = [UNIT].[UNIT_ID] LEFT OUTER JOIN [WAREHOUSE] ON [MO_RECEIPT_REQUISTION_D].[WAREHOUSE_ID]=[WAREHOUSE].[WAREHOUSE_ID] LEFT OUTER JOIN [BIN] ON [MO_RECEIPT_REQUISTION_D].[BIN_ID] = [BIN].[BIN_ID] LEFT OUTER JOIN [ITEM_LOT] ON [MO_RECEIPT_REQUISTION_D].[ITEM_LOT_ID] = [ITEM_LOT].[ITEM_LOT_ID] LEFT JOIN [UNIT] AS UNIT_02 --第二单位(参考单位) ON ITEM.SECOND_UNIT_ID = UNIT_02.[UNIT_ID] LEFT JOIN dbo.UNIT AS UNIT_04 --库存单位 ON ITEM.STOCK_UNIT_ID=UNIT_04.[UNIT_ID] WHERE
[MO_RECEIPT_REQUISTION].[DOC_NO] = #{docNo}
AND [MO_RECEIPT_REQUISTION].[ApproveStatus]=N'Y' AND [MO_RECEIPT_REQUISTION_D].[CLOSE]=N'0' AND MO_RECEIPT_REQUISTION_D.ACCEPTED_QTY +MO_RECEIPT_REQUISTION_D.CONCESSION_QTY-MO_RECEIPT_REQUISTION_D.RECEIPT_QTY > 0 GROUP BY [MO_RECEIPT_REQUISTION].[DOC_NO] ,[MO_RECEIPT_REQUISTION].[DOC_DATE] ,[ADMIN_UNIT].[ADMIN_UNIT_CODE] ,[ADMIN_UNIT].[ADMIN_UNIT_NAME] ,[EMPLOYEE].[EMPLOYEE_CODE] ,[EMPLOYEE].[EMPLOYEE_NAME] ,[ITEM].[ITEM_CODE] ,[ITEM_FEATURE].[ITEM_FEATURE_CODE] ,[MO_RECEIPT_REQUISTION_D].[ITEM_DESCRIPTION] ,[MO_RECEIPT_REQUISTION_D].[ITEM_SPECIFICATION] ,[UNIT].[UNIT_CODE] ,[WAREHOUSE].[WAREHOUSE_CODE] ,[BIN].[BIN_CODE] ,[ITEM_LOT].[LOT_CODE] ,UNIT.UNIT_NAME ,UNIT_02.UNIT_CODE ,UNIT_02.UNIT_NAME ,UNIT_04.UNIT_CODE ,UNIT_04.UNIT_NAME ,UNIT_04.DICIMAL_DIGIT ,ITEM.SECOND_UNIT_ID ,UNIT.UNIT_ID ,ITEM.ITEM_BUSINESS_ID ,ITEM.STOCK_UNIT_ID

SELECT DISTINCT B.DOC_NO docNo, B.DOC_DATE, C.ITEM_CODE itemCode, C.ITEM_NAME itemName, C.ITEM_SPECIFICATION itemSpec, A.REQUEST_QTY requestQty, A.ISSUE_RECEIPT_QTY issueReceiptQty, D.WAREHOUSE_CODE warehouseCode, Z.UDF021 binCode, U.UNIT_NAME unitName, U.UNIT_CODE unitCode, MOCTA.TA033 customerNo, M.DOC_NO MoDocNom, PLANT.PLANT_CODE AS shjg FROM ISSUE_RECEIPT_REQ_D A LEFT JOIN UNIT U ON A.UNIT_ID = U.UNIT_ID LEFT JOIN ISSUE_RECEIPT_REQ B ON A.ISSUE_RECEIPT_REQ_ID=B.ISSUE_RECEIPT_REQ_ID LEFT JOIN ITEM C ON C.ITEM_BUSINESS_ID=A.ITEM_ID LEFT JOIN WAREHOUSE D ON D.WAREHOUSE_ID=A.WAREHOUSE_ID LEFT JOIN MO M ON M.MO_ID = A.MO_ID LEFT JOIN MOCTA ON M.MO_ID = MOCTA.MO_ID LEFT JOIN PLANT ON M.Owner_Org_ROid = PLANT.PLANT_ID LEFT JOIN ITEM_PLANT Z ON Z.ITEM_ID = C.ITEM_BUSINESS_ID AND M.Owner_Org_ROid = Z.Owner_Org_ROid WHERE A.[CLOSE]='0' AND B.DOC_NO IN
#{docNo}
AND D.WAREHOUSE_CODE IN
#{warehouse}
ORDER BY B.DOC_DATE , C.ITEM_CODE DESC

SELECT COUNT(1)
FROM picking_summary
WHERE create_by = #{createBy}
AND doc_no IN

    #{docNo}

AND warehouse_code IN

    #{warehouse}

SELECT id, item_code itemCode, business_qty businessQty, item_name itemName, item_spec itemSpec,
create_by createBy, create_time createTime, match_qty matchQty, doc_no docNo, unit_no unitNo,
bin_code binCode, warehouse_code warehouseCode, barcode barCode,customerNo, shjg shjg, mo_doc_no moDocNo, currect_num currectNum
FROM picking_summary WHERE 1=1

    AND item_code = #{itemCode}


    AND create_by = #{createBy}

SELECT ISNULL(RIGHT('0000' + CAST(MAX(CAST(RIGHT(barcode, 4) AS INT)) + 1 AS VARCHAR(4)), 4), '0001')
FROM bm_barcode_detail
WHERE barcode LIKE #{queryBarcode} + '%';

SELECT COUNT(1) FROM picking_summary
WHERE match_qty != business_qty
AND create_by = #{createBy}

SELECT id, barcode, moDocNo AS sourceNo, itemCode AS itemNo, itemName AS itemName, itemSpec AS itemSpec, qty, lotDate AS lotDate, warehouseCode AS warehouseCode, warehouseName AS warehouseName, unitNo AS unitNo, unitName AS unitName, shjg FROM mo_instorage_summary
AND createBy = #{createBy}
AND barcode = #{barcode}

SELECT MOCTY.TY003 planDate, TY009 productionLine, UDF51 planNo, TY001 + '-' + TY002 docNo, MO.UDF021 customerDocNo, ITEM.ITEM_CODE itemCode, ITEM.ITEM_NAME itemName, ITEM.ITEM_SPECIFICATION itemSpec, MO_D.REQU_INCLUDE_MULT_QTY requiredQty, ISNULL(agv_task_detail.qty, 0) preparedQty, OPERATION.OPERATION_CODE operationCode, OPERATION.OPERATION_NAME operationName FROM MOCTY LEFT JOIN MO ON MO.DOC_NO = MOCTY.TY001 + '-' + MOCTY.TY002 LEFT JOIN MO_D ON MO.MO_ID = MO_D.MO_ID LEFT JOIN OPERATION ON OPERATION.OPERATION_ID = MO_D.OPERATION_ID LEFT JOIN agv_process_info ON agv_process_info.processCode = OPERATION.OPERATION_CODE AND MOCTY.TY009 = agv_process_info.productionLine LEFT JOIN agv_warehouse ON agv_warehouse.id = agv_process_info.agvWarId LEFT JOIN ITEM ON ITEM.ITEM_BUSINESS_ID = MO_D.ITEM_ID LEFT JOIN ITEM_PLANT ON ITEM_PLANT.ITEM_ID = MO_D.ITEM_ID AND ITEM_PLANT.Owner_Org_ROid = MO.Owner_Org_ROid LEFT JOIN agv_task_detail ON agv_task_detail.docNo = MO.DOC_NO AND agv_task_detail.itemCode = ITEM.ITEM_CODE WHERE MOCTY.UDF51 IS NOT NULL AND MO_D.REQU_INCLUDE_MULT_QTY > ISNULL(agv_task_detail.qty, 0)
AND MOCTY.TY003 >= #{planDate}
AND MOCTY.TY009 = #{productionLine}
ORDER BY MOCTY.UDF51 ASC, OPERATION.OPERATION_CODE ASC
